sys_security_acl.script:
if (gs.hasRole('x_2097092_linq.platform_admin')) {
  answer = true;
} else if (gs.hasRole('x_2097092_linq.college_admin')) {
  // College admin writes clubs of their college
  var userCollege = gs.getUser().getRecord().getValue('u_college');
  answer = (current.getValue('college') == userCollege);
} else {
  // club_admin: write only clubs where they have active admin membership
  var gr = new GlideRecord('x_2097092_linq_club_membership');
  gr.addQuery('member', gs.getUserID());
  gr.addQuery('club', current.getUniqueValue());
  gr.addQuery('role', 'admin');
  gr.addQuery('status', 'active');
  gr.query();
  answer = gr.hasNext();
}
